import json

def main(json_text: str) -> dict:
    """
    解析传入的任务JSON字符串，提取每个任务的 task_id、tool、query
    :param json_text: 外部传入的完整json字符串参数（来自 llm_da855.output）
    :return: 包含任务列表的字典，供下游循环节点使用
    """
    try:
        data = json.loads(json_text)
        task_list = data.get("tasks", [])  # 增加健壮性，避免 KeyError
        
        result = []
        for task in task_list:
            extract_data = {
                "task_id": task.get("task_id"),
                "tool": task.get("tool"),
                "query": task.get("query")
            }
            result.append(extract_data)
        
        return {
            "tasks_info": result  # 下游通过 {{代码节点名.tasks_info}} 引用整个列表
        }
    except json.JSONDecodeError:
        # 如果规划节点输出格式有误，返回空列表，防止工作流报错中断
        return {"tasks_info": []}

import uuid

def main(task_list):
    MAX_TASK_LIMIT = 20

    valid_tasks = [
        task for task in task_list
        if task.get("tool") and task.get("query")
        and str(task["tool"]).strip()
        and str(task["query"]).strip()
    ][:MAX_TASK_LIMIT]

    return {
        "run_id": str(uuid.uuid4()),   # 每轮唯一ID
        "tasks": valid_tasks,
        "total_task_count": len(valid_tasks),
        "current_index": 0,
        "result_list": []
    }

def main(tasks, current_index):
    # 强制转换为整数
    idx = int(current_index)
    task = tasks[idx]
    return {
        "current_task_id": task.get("task_id", f"task_{idx + 1}"),
        "current_tool_type": task.get("tool", "").strip(),
        "current_query": task.get("query", "").strip()
    }

def main(tasks, current_index, result_list,run_id,sql_result="", rag_result="", web_result=""):
    idx = int(current_index)
    current_task = tasks[idx]

    # 自动取当前分支的有效执行结果
    current_task_result = ""
    if sql_result and sql_result.strip():
        current_task_result = sql_result.strip()
    elif rag_result and rag_result.strip():
        current_task_result = rag_result.strip()
    elif web_result and web_result.strip():
        current_task_result = web_result.strip()

    result_item = {
        "task_id": current_task.get("task_id", f"task_{idx + 1}"),
        "tool_type": current_task.get("tool", ""),
        "query": current_task.get("query", ""),
        "execute_result": current_task_result
    }

    new_result_list = result_list.copy() if result_list else []
    new_result_list.append(result_item)
    new_index = str(idx + 1)

    return {
        "tasks": tasks,
        "current_index": new_index,
        "result_list": new_result_list,
        "run_id": run_id
    }

