def main(result_list):
    
    if not result_list:
        return {"has_valid_result": "false"}
    
    valid_count = 0
    for task in result_list:
        res = task.get("execute_result", "").strip()
        # 有效结果判定：非空、不是纯空格、不包含失败标记
        if res and res != " " and "查询失败" not in res:
            valid_count += 1
    
    return {
        "has_valid_result": "true" if valid_count > 0 else "false",
        "valid_count": str(valid_count)
    }

import re

def main(sql_text: str) -> dict:
    sql = sql_text.strip()
    
    # 定义所有合法的带库名的表名模式
    valid_table_patterns = [
        r"gxy_streaming\.gxy_",
        r"gxy_dw\.(dwd_|dim_)",
        r"core_db\.(enterprise)"
    ]
    
    # 检查是否包含未带库名的裸表（简单匹配核心表名）
    bare_table_keywords = [
        "gxy_students", "gxy_attendance", "gxy_report",
        "dwd_job_detail", "dim_job_position", "enterprise"
    ]
    
    has_bare_table = False
    for keyword in bare_table_keywords:
        # 匹配前面不带库名前缀的表名
        pattern = r"(?<!\.)" + re.escape(keyword)
        if re.search(pattern, sql, re.IGNORECASE):
            has_bare_table = True
            break
    
    # 检查是否有合法的带库名表
    has_valid_table = False
    for pattern in valid_table_patterns:
        if re.search(pattern, sql, re.IGNORECASE):
            has_valid_table = True
            break
    
    if has_bare_table or not has_valid_table:
        return {"is_valid": "false", "checked_sql": sql}
    else:
        return {"is_valid": "true", "checked_sql": sql}
